import{_ as a,o as l,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const q=JSON.parse('{"title":"1995年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1995年/核心总结.md","filePath":"01_letters/1995年/核心总结.md"}'),e={name:"01_letters/1995年/核心总结.md"};function i(n,t,h,s,d,u){return l(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="_1995年巴菲特致股东信核心要点" tabindex="-1">1995年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1995年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1995年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增长45.0%（53亿美元）</li><li>每股账面价值增长43.1%</li><li>31年复合增长率：23.6%</li><li>发行1.3%新股用于收购</li></ul><hr><h2 id="_1995年三大收购" tabindex="-1">1995年三大收购 <a class="header-anchor" href="#_1995年三大收购" aria-label="Permalink to &quot;1995年三大收购&quot;">​</a></h2><h3 id="_1-geico保险公司" tabindex="-1">1. GEICO保险公司 <a class="header-anchor" href="#_1-geico保险公司" aria-label="Permalink to &quot;1. GEICO保险公司&quot;">​</a></h3><ul><li><strong>收购价格</strong>：230亿美元（1996年初完成）</li><li><strong>收购比例</strong>：100%（之前持有50%）</li><li><strong>关键人物</strong>：托尼·尼cely（Tony Nicely）CEO</li><li><strong>历史渊源</strong>：巴菲特1951年首次投资GEICO</li></ul><h3 id="_2-helzberg钻石店" tabindex="-1">2. Helzberg钻石店 <a class="header-anchor" href="#_2-helzberg钻石店" aria-label="Permalink to &quot;2. Helzberg钻石店&quot;">​</a></h3><ul><li><strong>性质</strong>：珠宝零售连锁</li><li><strong>创始人</strong>：Helzberg家族</li><li><strong>CEO</strong>：Jeff Comment</li></ul><h3 id="_3-rc威利家居" tabindex="-1">3. RC威利家居 <a class="header-anchor" href="#_3-rc威利家居" aria-label="Permalink to &quot;3. RC威利家居&quot;">​</a></h3><ul><li><strong>创始人</strong>：Bill Child</li><li><strong>销售规模</strong>：2.57亿美元</li><li><strong>市场地位</strong>：犹他州最大家居零售商</li></ul><hr><h2 id="双重投资策略" tabindex="-1">双重投资策略 <a class="header-anchor" href="#双重投资策略" aria-label="Permalink to &quot;双重投资策略&quot;">​</a></h2><p>巴菲特提出&quot;双管齐下&quot;策略：</p><ol><li><strong>整体收购</strong>：通过谈判收购整个企业</li><li><strong>股票投资</strong>：在市场上购买部分股权</li></ol><blockquote><p>伍迪·艾伦：&quot;双性恋的优势在于周六晚上的约会机会加倍。&quot;</p></blockquote><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="浮存金数据-1995" tabindex="-1">浮存金数据（1995） <a class="header-anchor" href="#浮存金数据-1995" aria-label="Permalink to &quot;浮存金数据（1995）&quot;">​</a></h3><ul><li>浮存金：$3,607.2M</li><li>成本：<strong>负</strong>（盈利）</li><li>1967-1995年：28年中有21年成本为负</li></ul><h3 id="geico的成功" tabindex="-1">GEICO的成功 <a class="header-anchor" href="#geico的成功" aria-label="Permalink to &quot;GEICO的成功&quot;">​</a></h3><ul><li>1995年保费增长23%</li><li>承保利润59%增长</li><li>直销模式成本优势明显</li></ul><h3 id="超级巨灾保险" tabindex="-1">超级巨灾保险 <a class="header-anchor" href="#超级巨灾保险" aria-label="Permalink to &quot;超级巨灾保险&quot;">​</a></h3><ul><li>1995年盈利</li><li>托尼·泰森保单、Lloyd&#39;s保险、中国卫星发射等创新业务</li></ul><hr><h2 id="普通股持仓-1995年底" tabindex="-1">普通股持仓（1995年底） <a class="header-anchor" href="#普通股持仓-1995年底" aria-label="Permalink to &quot;普通股持仓（1995年底）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>持股</th><th>市值</th></tr></thead><tbody><tr><td>可口可乐</td><td>100M股</td><td>$7,425M</td></tr><tr><td>大都会/ABC</td><td>20M股</td><td>$2,468M</td></tr><tr><td>GEICO</td><td>34.25M股</td><td>$2,393M</td></tr><tr><td>吉列</td><td>48M股</td><td>$2,502M</td></tr><tr><td>富国银行</td><td>6.79M股</td><td>$1,467M</td></tr></tbody></table><hr><h2 id="股票分割与b股创建" tabindex="-1">股票分割与B股创建 <a class="header-anchor" href="#股票分割与b股创建" aria-label="Permalink to &quot;股票分割与B股创建&quot;">​</a></h2><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h3><ul><li>当时股价：$36,000</li><li>原因：防止&quot;克隆&quot;基金的销售</li></ul><h3 id="方案" tabindex="-1">方案 <a class="header-anchor" href="#方案" aria-label="Permalink to &quot;方案&quot;">​</a></h3><ul><li>创建Class B股票</li><li>1股B = 1/30股A的权益</li><li>B股投票权：1/200的A</li></ul><h3 id="巴菲特的观点" tabindex="-1">巴菲特的观点 <a class="header-anchor" href="#巴菲特的观点" aria-label="Permalink to &quot;巴菲特的观点&quot;">​</a></h3><blockquote><p>&quot;我不认为伯克希尔被低估。&quot;</p></blockquote><hr><h2 id="错误与教训" tabindex="-1">错误与教训 <a class="header-anchor" href="#错误与教训" aria-label="Permalink to &quot;错误与教训&quot;">​</a></h2><h3 id="_1-1989年吉列投资" tabindex="-1">1. 1989年吉列投资 <a class="header-anchor" href="#_1-1989年吉列投资" aria-label="Permalink to &quot;1. 1989年吉列投资&quot;">​</a></h3><ul><li>购买优先股而非普通股</li><li>如果买普通股可多赚$625M</li><li>这是&quot;最大错误&quot;（虽然财务报表未体现）</li></ul><h3 id="_2-usair优先股" tabindex="-1">2. USAir优先股 <a class="header-anchor" href="#_2-usair优先股" aria-label="Permalink to &quot;2. USAir优先股&quot;">​</a></h3><ul><li>仍在亏损</li><li>航空业成本问题难以解决</li></ul><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><ol><li><p><strong>关于收购</strong>：</p><blockquote><p>&quot; HMS Pinafore中的歌词：&#39;事物往往不是它们看起来的那样，脱脂牛奶伪装成奶油。&#39;&quot;</p></blockquote></li><li><p><strong>关于管理层</strong>：</p><blockquote><p>&quot;在零售业，持续聪明是必须的。 coasts就是失败。&quot;</p></blockquote></li><li><p><strong>关于长期视角</strong>：</p><blockquote><p>&quot;如果你的持有期是10年，不要考虑持有10分钟。&quot;</p></blockquote></li><li><p><strong>关于GEICO</strong>：</p><blockquote><p>&quot;GEICO是我的第一个商业恋人。&quot;</p></blockquote></li></ol><hr><h2 id="_1995年启示" tabindex="-1">1995年启示 <a class="header-anchor" href="#_1995年启示" aria-label="Permalink to &quot;1995年启示&quot;">​</a></h2><ol><li><strong>优秀企业值得溢价</strong>：GEICO、喜诗糖果等案例</li><li><strong>直销模式的优势</strong>：低成本→低价格→更多客户→更低成本</li><li><strong>管理层的重要性</strong>：找到优秀的管理者是成功的关键</li><li><strong>复利的力量</strong>：长期持有优秀企业</li><li><strong>避免&quot;时尚&quot;收购</strong>：不做分散注意力的多元化</li></ol>',47)])])}const b=a(e,[["render",i]]);export{q as __pageData,b as default};
